#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 3e5+5;
struct Query{LL l,r,x,y,z,id;}q[N];
LL n,m,Q,val[N],wxq[N],col[N];
LL dep[N],sz[N],son[N],Fa[N];
LL Top[N],dfn[N],cnt,lis[N];
vector<int> g[N];pii tn[N];
LL rQ,St,Siz,L,R,T;bool vis[N];
LL c[N],nowAns,ans[N];
bool cmp(Query q1,Query q2){
    if(q1.x!=q2.x)return q1.x<q2.x;
    if(q1.y!=q2.y)return (q1.x&1?q1.y<q2.y:q1.y>q2.y);
    return ((q1.x^q1.y)%2==1?q1.z<q2.z:q1.z>q2.z);
}
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS_init(int u){
    dep[u]=dep[Fa[u]]+1,sz[u]=1;
    for(int v:g[u])if(v^Fa[u]){
        Fa[v]=u,DFS_init(v),sz[u]+=sz[v];
        if(sz[v]>sz[son[u]])son[u]=v;
    }return;
}
void DFS_mkl(int u,int p){
    Top[u]=p,dfn[u]=(++cnt);
    lis[dfn[u]]=u;
    if(son[u])DFS_mkl(son[u],p);
    for(int v:g[u])if(v^Fa[u]&&v^son[u])DFS_mkl(v,v);
    lis[++cnt]=u;return;
}
int LCA(int u,int v){
    while(Top[u]!=Top[v])
        if(dep[Top[u]]>dep[Top[v]])u=Fa[Top[u]];
        else v=Fa[Top[v]];
    return (dep[u]<dep[v]?u:v);
}
void Sol(int p){
    int x=col[p];vis[p]^=1;
    if(vis[p])nowAns+=wxq[++c[x]]*val[x];
    else nowAns-=wxq[c[x]--]*val[x];return;
}
void Mov(int p){
    auto [u,x]=tn[p];int y=col[u];
    if(vis[u])
        nowAns+=wxq[++c[x]]*val[x],
        nowAns-=wxq[c[y]--]*val[y];
    tn[p].se=y,col[u]=x;return;
}
int main(){
    n=read(),m=read(),Q=read();
    for(int i=1;i<=m;i++)val[i]=read();
    for(int i=1;i<=n;i++)wxq[i]=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }for(int i=1;i<=n;i++)col[i]=read();
    DFS_init(1);DFS_mkl(1,1);
    while(Q--){
        int opt=read(),x=read(),y=read();
        if(opt){
            if(dfn[x]>dfn[y])swap(x,y);
            q[++rQ]={x,y,dfn[x],dfn[y],St,rQ};
        }else tn[++St]={x,y};
    }Siz=pow(n,(St?2.0/3:1.0/2));
    for(int i=1;i<=rQ;i++)q[i].x/=Siz,q[i].y/=Siz;
    sort(q+1,q+rQ+1,cmp);
    L=dfn[q[1].l],R=L-1,T=0;
    for(int i=1;i<=rQ;i++){
        auto [u,v,x,y,tim,id]=q[i];
        x=dfn[u],y=dfn[v];
        while(L>x)Sol(lis[--L]);
        while(R<y)Sol(lis[++R]);
        while(L<x)Sol(lis[L++]);
        while(R>y)Sol(lis[R--]);
        while(T<tim)Mov(++T);
        while(T>tim)Mov(T--);
        int w=LCA(u,v);
        if(u!=w){Sol(u);if(v!=w)Sol(w);}
        ans[id]=nowAns;
        if(u!=w){Sol(u);if(v!=w)Sol(w);}
    }for(int i=1;i<=rQ;i++)cout<<ans[i]<<"\n";
    return 0;
}
